import{_ as t,o,c as a,a2 as i}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"SOP-012: Policy & Gate Exceptions","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-012-exception-handling.md","filePath":"sops/SOP-012-exception-handling.md","lastUpdated":1782929962000}'),r={name:"sops/SOP-012-exception-handling.md"};function n(s,e,l,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="sop-012-policy-gate-exceptions" tabindex="-1">SOP-012: Policy &amp; Gate Exceptions <a class="header-anchor" href="#sop-012-policy-gate-exceptions" aria-label="Permalink to &quot;SOP-012: Policy &amp; Gate Exceptions&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Security (security exceptions) / EM (process exceptions)</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Documented, time-bound exceptions when CI gates or policies cannot be met. <strong>Default: fix forward, not except.</strong></p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>SEC</td><td><strong>A</strong> — security scan / data policy exceptions</td></tr><tr><td>EM</td><td><strong>A</strong> — process/timeline exceptions</td></tr><tr><td>ARCH</td><td>C — architectural exceptions</td></tr><tr><td>DEV</td><td>R — exception request</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Blocked merge or deploy with documented failure</li><li>Good-faith effort to remediate (link to attempt PR or ticket)</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Request</strong> — Ticket template: gate failed, reason, blast radius, proposed expiry, compensating controls.</li><li><strong>Risk assessment</strong> — SEC (security) or ARCH (design) documents risk score.</li><li><strong>Approve or deny</strong> — Approver comments on ticket; deny → must fix forward.</li><li><strong>Record</strong> — If approved: exception ID, expiry date (max 30 days security, 14 days other), compensating control (e.g., manual SRE review, WAF rule).</li><li><strong>CI label</strong> — <code>exception-SEC-123</code> applied; pipeline allows specific gate skip (audited).</li><li><strong>Renewal</strong> — Requires new approval; max 1 renewal.</li><li><strong>Close</strong> — Remediation PR merged; exception revoked.</li></ol><h2 id="non-exceptionable" tabindex="-1">Non-exceptionable <a class="header-anchor" href="#non-exceptionable" aria-label="Permalink to &quot;Non-exceptionable&quot;">​</a></h2><ul><li>Production customer PII in AI prompts</li><li>Merge with active Critical secret scan finding</li><li>Deploy T1 without canary</li><li>Skip contract tests on API changes</li></ul><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Exception ticket approved with expiry</li><li>[ ] Compensating control active</li><li>[ ] Remediation tracked before expiry</li></ul><h2 id="sla" tabindex="-1">SLA <a class="header-anchor" href="#sla" aria-label="Permalink to &quot;SLA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Review SLA</th></tr></thead><tbody><tr><td>Security</td><td>1 business day</td></tr><tr><td>Process</td><td>2 business days</td></tr></tbody></table><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-005-pr-review.html">SOP-005</a> · <a href="./SOP-010-ai-tool-usage.html">SOP-010</a> · <a href="./../GOVERNANCE.html">GOVERNANCE.md</a></li></ul>',18)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
